#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // A: MxM, B: MxN
    // Transform:  B := alpha * A^T * B
    // Equivalent to: B[i][j] = alpha * sum_{k=i+1}^{M-1} A[k][i] * B[k][j]

    // Parallelize the outer two loops with OpenMP.
    // Inner k-loop is small enough that vectorization is not needed when
    // the data fits into cache.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * sum;
        }
    }
}
