#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    /* Parallelise the outer loop. All iterations are independent,
       so a static schedule works well on a shared‑memory system. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Update column i, rows 0 .. i-1 */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            /* Accumulate dot product A[i][k] * A[j][k] for k < j */
            for (int k = 0; k < j; ++k) {
                sum += A[i][k] * A[j][k];
            }
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        /* Compute the diagonal element A[i][i] */
        double diag = 0.0;
        for (int k = 0; k < i; ++k) {
            diag += A[i][k] * A[i][k];
        }
        A[i][i] = std::sqrt(A[i][i] - diag);
    }
}
