#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    /* Use raw pointers to avoid vector bounds checks inside the hot loops.
       The vector memory is contiguous, so this is safe as long as the
       supplied vectors have size >= n. */
    double* a = A.data();
    double* b = B.data();

    const double coef = 0.33333;
    const int last = n - 1;

    /* Parallelise the inner domain loops on the outer time loop.
       Each iteration of t is independent, so a simple parallel loop per
       time step is sufficient. */
    for (int t = 0; t < tsteps; ++t) {
#pragma omp parallel for schedule(static)
        for (int i = 1; i < last; ++i) {
            b[i] = coef * (a[i-1] + a[i] + a[i+1]);
        }

#pragma omp parallel for schedule(static)
        for (int i = 1; i < last; ++i) {
            a[i] = coef * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
