#include <vector>
#include <omp.h>

void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {
    // Row‑major access: A[i][j] = A_flat[i*m + j]
    // For better cache usage we convert the 2‑D vector to a flat pointer
    const double* a_flat = A[0].data();   // Assumes A is a proper m×n block
    const double* p_ptr   = p.data();
    const double* r_ptr   = r.data();
    double*       s_ptr   = s.data();
    double*       q_ptr   = q.data();

    // Zero the s vector
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) s_ptr[j] = 0.0;

    // Compute s = Aᵀ * r  and  q = A * (1 + p)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double qi = 0.0;
        const double* a_row = a_flat + i * m;
        const double ai = r_ptr[i];
        for (int j = 0; j < m; ++j) {
            double val = a_row[j];
            #pragma omp atomic
            s_ptr[j] += ai * val;          // s += r[i] * A[i][j]
            qi += val + p_ptr[j];          // q[i] += A[i][j] + p[j]
        }
        q_ptr[i] = qi;
    }
}
