#include <vector>
#include <omp.h>

void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // Convert each row vector to a raw pointer for faster access
    std::vector<double*> c_ptr(n), a_ptr(n);
    for (int i = 0; i < n; ++i) {
        c_ptr[i] = C[i].data();
        a_ptr[i] = A[i].data();
    }

    // Parallel over the outer dimension i
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* ci = c_ptr[i];
        double* ai = a_ptr[i];

        // C[i][j] = beta * C[i][j]   for j <= i
        for (int j = 0; j <= i; ++j) {
            ci[j] *= beta;
        }

        // Accumulate the rank‑k update
        for (int k = 0; k < m; ++k) {
            double aik = ai[k];
            if (aik == 0.0) continue;               // avoid useless work
            double* aj = a_ptr[k];
            // j <= i
            for (int j = 0; j <= i; ++j) {
                ci[j] += alpha * aik * aj[j];
            }
        }
    }
}
