/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {
    // Get raw pointers for fast indexing
    double* sum_arr = sum.data();                      // [np]
    double** C4_ptr = new double*[np];                 // [np][np]
    for (int s = 0; s < np; ++s) {
        C4_ptr[s] = C4[s].data();                      // C4[s][*]
    }

    // Force contiguous 3‑D access by flattening the index calculations
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            double* A_rq = A[r][q].data();             // [np]
            for (int p = 0; p < np; ++p) {
                double prod = 0.0;
                // unroll inner loop if small (optional)
                for (int s = 0; s < np; ++s) {
                    prod += A_rq[s] * C4_ptr[s][p];
                }
                sum_arr[p] = prod;                      // reuse sum for later copy
            }
            // copy back to A
            for (int p = 0; p < np; ++p) {
                A_rq[p] = sum_arr[p];
            }
        }
    }

    delete[] C4_ptr;
}
