syr2k:
```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    // Use OpenMP to parallelise over the outermost dimension
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* const cRow = C[i].data();          // pointer to row i of C
        const double* const aRow = A[i].data();    // pointer to row i of A
        const double* const bRow = B[i].data();    // pointer to row i of B

        // 1) scale the lower triangular part of C[i,*] by beta
        for (int j = 0; j <= i; ++j) {
            cRow[j] *= beta;
        }

        // 2) compute the rank‑2 update
        // We keep a local copy of alpha to avoid repeated loads.
        const double a = alpha;
        for (int k = 0; k < m; ++k) {
            const double* const aCol = A[k].data(); // A[*,k]
            const double* const bCol = B[k].data(); // B[*,k]
            const double aik = aRow[k] * a;         // A[i][k] * alpha
            const double bik = bRow[k] * a;         // B[i][k] * alpha

            for (int j = 0; j <= i; ++j) {
                cRow[j] += aCol[j] * bRow[k] + bCol[j] * aik;
            }
        }
    }
}
```
This implementation keeps the same external behaviour, uses direct pointer access for cache friendliness, pre‑computes constants, and parallelises the outer loop with OpenMP for multicore speed‑ups.

