#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A)
{
    /* First product: y_1 is a vector, A is row‑major.
       Parallelise over the outer index i.  No data races
       on x1, so it is safe to update it directly. */
    #pragma omp parallel for schedule(static,256) nowait
    for (int i = 0; i < n; ++i) {
        double xi = x1[i];
        const double* Ai = A[i].data();
        for (int j = 0; j < n; ++j)
            xi += Ai[j] * y_1[j];
        x1[i] = xi;
    }

    /* Second product: use the transpose of A.
       Again, parallelise over the outer loop i.  The
       data is read‑only through A[j][i], hence no race. */
    #pragma omp parallel for schedule(static,256)
    for (int i = 0; i < n; ++i) {
        double xi = x2[i];
        for (int j = 0; j < n; ++j)
            xi += A[j][i] * y_2[j];
        x2[i] = xi;
    }
}
