#include <vector>
#include <cstddef>
#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* Flatten the input data into a contiguous buffer for better cache locality */
    std::vector<double> flat_data(static_cast<std::size_t>(n) * m);
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[static_cast<std::size_t>(i) * m + j] = data[i][j];

    /* Compute column means */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += flat_data[static_cast<std::size_t>(i) * m + j];
        mean[j] = sum / n;
    }

    /* Zero‑center the data */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[static_cast<std::size_t>(i) * m + j] -= mean[j];

    /* Compute covariance matrix (upper triangle) */
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += flat_data[static_cast<std::size_t>(k) * m + i] *
                       flat_data[static_cast<std::size_t>(k) * m + j];
            cov[i][j] = sum / (n - 1);
            if (i != j)
                cov[j][i] = cov[i][j];
        }
    }

    /* Update the original 2‑D vector with the centered data */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] = flat_data[static_cast<std::size_t>(i) * m + j];
}
