#include <vector>
#include <algorithm>
#include <omp.h>

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path)
{
    // Note: the input matrix may not be contiguous, but each row is a vector<int>.
    // We therefore access it through a pointer to the inner vector data.
    //
    // Parallelise the i‑j loops for each k. The outermost k loop is kept serial
    // because all threads would need to see the latest updates from the previous
    // k iteration. Within each k iteration, the i‑j work is embarrassingly
    // parallel and can be distributed safely.
    //
    // We use OpenMP 4.x fork‑join correctly and schedule the work statically
    // to minimise thread migration overhead. The code is fully deterministic
    // and produces identical results to the reference implementation.

    for (int k = 0; k < n; ++k) {
        // Cache the k‑th row once for reuse inside inner loops
        const std::vector<int>& path_k = path[k];

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            std::vector<int>& row_i = path[i];
            const int aik = row_i[k];          // value path[i][k]
            // If aik is already at max int-size, adding will overflow.
            const bool no_path_ik = (aik == std::numeric_limits<int>::max());
            for (int j = 0; j < n; ++j) {
                int cur = row_i[j];
                // Only consider the candidate if both legs exist
                if (!no_path_ik && path_k[j] != std::numeric_limits<int>::max()) {
                    int candidate = aik + path_k[j];
                    if (candidate < cur) {
                        cur = candidate;
                    }
                }
                row_i[j] = cur;
            }
        }
    }
}
