```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* ------------------------------------------------------------------
       Matrix‑multiply A(ni×nk) * B(nk×nj) → tmp(ni×nj)
    ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const tmp_i = tmp[i].data();
        const double* const A_i = A[i].data();
        for (int j = 0; j < nj; ++j) {
            double acc = 0.0;
            const double* B_col = &B[0][j];          // pointer to first element of column j
            for (int k = 0; k < nk; ++k) {
                acc += alpha * A_i[k] * B_col[k*nj]; // B_col is effectively B[k][j]
            }
            tmp_i[j] = acc;
        }
    }

    /* ------------------------------------------------------------------
       Matrix‑multiply tmp(ni×nj) * C(nj×nl) → D(ni×nl)
       scaling D by beta before accumulation
    ------------------------------------------------------------------ */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* const D_i = D[i].data();
        const double* const tmp_i = tmp[i].data();
        for (int j = 0; j < nl; ++j) {
            double acc = D_i[j] * beta;
            const double* C_col = &C[0][j];
            for (int k = 0; k < nj; ++k) {
                acc += tmp_i[k] * C_col[k*nl];       // C_col refers to C[k][j]
            }
            D_i[j] = acc;
        }
    }
}
