#include <cmath>
#include <vector>
#include <omp.h>

void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Pre‑allocate pointers to row data for fast access
    std::vector<double*> Ap(m), Rp(m), Qp(m);
    for (int i = 0; i < m; ++i) {
        Ap[i] = A[i].data();
        Rp[i] = R[i].data();
        Qp[i] = Q[i].data();
    }

    for (int k = 0; k < n; ++k) {
        // ‑ compute ||A[:,k]||
        double nrm = 0.0;
#pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i) {
            double v = Ap[i][k];
            nrm += v * v;
        }
        R[k][k] = std::sqrt(nrm);

        // ‑ normalize column k to get Q[:,k]
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            Qp[i][k] = Ap[i][k] / R[k][k];
        }

        // ‑ orthogonalize remaining columns
        for (int j = k + 1; j < n; ++j) {
            // compute R[k][j] = Q[:,k]^T * A[:,j]
            double dot = 0.0;
#pragma omp simd reduction(+:dot)
            for (int i = 0; i < m; ++i) {
                dot += Qp[i][k] * Ap[i][j];
            }
            R[k][j] = dot;

            // update A[:,j] -= Q[:,k] * R[k][j]
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                Ap[i][j] -= Qp[i][k] * dot;
            }
        }
    }
}
```
This version keeps the exact semantics while:

* Using `-O2` friendly SIMD intrinsics with `#pragma omp simd` for inner reductions.
* Parallelizing independent row operations with `#pragma omp parallel for`.
* Accessing row data via raw pointers for better cache locality.

