```cpp
#include <vector>
#include <cstring>
#include <algorithm>
#include <cstddef>
#include <cmath>

/* Optimised Durbin recursion kernel.
 *   - Uses raw pointers and minimal bounds checking.
 *   - Avoids unnecessary vector indexing.
 *   - Keeps the original algorithmic behaviour exactly.
 */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate temporary buffer once
    std::vector<double> z(n);

    // Raw pointers for speed
    double* ry = r.data();
    double* yy = y.data();
    double* zy = z.data();

    yy[0] = -ry[0];
    double beta  = 1.0;
    double alpha = -ry[0];

    for (int k = 1; k < n; ++k) {
        // Update beta first
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = sum_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        const double* rptr = ry + k - 1;   // points to r[k-1]
        const double* yptr = yy;           // points to y[0]
        for (int i = 0; i < k; ++i, --rptr, ++yptr) {
            sum += (*rptr) * (*yptr);
        }

        // New reflection coefficient
        alpha = -(ry[k] + sum) / beta;

        // Compute new y[0..k-1] into z
        // z[i] = y[i] + alpha * y[k-i-1]
        const double* y_left  = yy;                         // y[0]
        const double* y_right = yy + k - 1;                  // y[k-1]
        for (int i = 0; i < k; ++i, ++y_left, --y_right) {
            zy[i] = *y_left + alpha * (*y_right);
        }

        // Copy back to y[0..k-1]
        std::memcpy(yy, zy, k * sizeof(double));

        // Set the new entry
        yy[k] = alpha;
    }
}
