   including the call and return. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const int last = n - 1;
    const double coef = 0.2;

    /* Ensure that the inner vectors have the expected size.
       The harness guarantees proper dimensions, so this is only
       a defensive check to keep the semantics unchanged. */
    for (int i = 0; i < n; ++i) {
        if ((int)A[i].size() != n || (int)B[i].size() != n) {
            /* In a real benchmark we might exit or throw, but here we
               simply return to preserve behaviour. */
            return;
        }
    }

    for (int t = 0; t < tsteps; ++t) {
        /* First update: B from A */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < last; ++i) {
            double* Arow   = A[i].data();
            double* Arowm1 = A[i - 1].data();
            double* Arowp1 = A[i + 1].data();
            double* Brow   = B[i].data();
            for (int j = 1; j < last; ++j) {
                Brow[j] = coef * (Arow[j] + Arow[j - 1] + Arow[j + 1] +
                                  Arowp1[j] + Arowm1[j]);
            }
        }

        /* Second update: A from B */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < last; ++i) {
            double* Brow   = B[i].data();
            double* Browm1 = B[i - 1].data();
            double* Browp1 = B[i + 1].data();
            double* Arow   = A[i].data();
            for (int j = 1; j < last; ++j) {
                Arow[j] = coef * (Brow[j] + Brow[j - 1] + Brow[j + 1] +
                                  Browp1[j] + Browm1[j]);
            }
        }
    }
}
