/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y) {

    /* Parallelise over the outer dimension.  Each iteration
       writes to distinct elements of tmp and y, so no
       synchronization is needed. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Work with raw pointers for speed. */
        const double* const aRow = A[i].data();
        const double* const bRow = B[i].data();
        const double* const xPtr = x.data();

        double sumA = 0.0;
        double sumB = 0.0;

        /* Unroll the inner loop by 4 for a modest speedup on
           many SIMD capable CPUs. */
        int j = 0;
        const int unroll = 4;
        const int limit = n - (n % unroll);
        for (; j < limit; j += unroll) {
            sumA += aRow[j]     * xPtr[j];
            sumB += bRow[j]     * xPtr[j];
            sumA += aRow[j + 1] * xPtr[j + 1];
            sumB += bRow[j + 1] * xPtr[j + 1];
            sumA += aRow[j + 2] * xPtr[j + 2];
            sumB += bRow[j + 2] * xPtr[j + 2];
            sumA += aRow[j + 3] * xPtr[j + 3];
            sumB += bRow[j + 3] * xPtr[j + 3];
        }
        for (; j < n; ++j) {
            sumA += aRow[j] * xPtr[j];
            sumB += bRow[j] * xPtr[j];
        }

        /* Store the results for this row. */
        tmp[i] = sumA;
        y[i]   = alpha * sumA + beta * sumB;
    }
}
