        auto& Ai   = A[i];
        double ui1 = u1[i];
        double ui2 = u2[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    // 2. Left multiplication by A^T
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += beta * A[j][i] * y[j];
        }
        x[i] += sum;
