#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    constexpr double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ---------- 1. Compute mean ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    /* ---------- 2. Compute stddev (and clamp small values) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mu;
            sum_sq += diff * diff;
        }
        double dev = std::sqrt(sum_sq / static_cast<double>(n));
        stddev[j] = (dev <= eps) ? 1.0 : dev;
    }

    /* ---------- 3. Normalize data ---------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double v = data[i][j] - mean[j];
            data[i][j] = v * inv_sqrt_n / stddev[j];
        }
    }

    /* ---------- 4. Compute correlation matrix ---------- */
    // diag first
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
    }

    // upper triangle
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = s;
            corr[j][i] = s;
        }
    }

    /* Last diagonal already set above, but kept for clarity */
    corr[m-1][m-1] = 1.0;
}
