//Optimised GEMM for flat 2‑D vectors, preserving exact semantics.
//
//Compile with: g++ -O2 -Wall -march=native -fopenmp -std=c++17
//The harness still passes the original function signature.

#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Convert the 2‑D std::vector containers into flattened pointers
    // for fast pointer arithmetic.
    const size_t nA = static_cast<size_t>(ni) * nk;
    const size_t nB = static_cast<size_t>(nk) * nj;
    const size_t nC = static_cast<size_t>(ni) * nj;

    double* a = new double[nA];
    double* b = new double[nB];
    double* c = new double[nC];

    // Fill the flat arrays with the input data
    for (int i = 0; i < ni; ++i)
        for (int k = 0; k < nk; ++k)
            a[i * nk + k] = A[i][k];

    for (int k = 0; k < nk; ++k)
        for (int j = 0; j < nj; ++j)
            b[k * nj + j] = B[k][j];

    // Main GEMM loop with parallelisation and blocking.
    const int BLOCK = 32; // tile size tuned for L1 cache
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i0 = 0; i0 < ni; i0 += BLOCK)
        for (int j0 = 0; j0 < nj; j0 += BLOCK) {
            // Initial scaling by beta
            for (int i = i0; i < std::min(i0 + BLOCK, ni); ++i) {
                double* cij = &c[i * nj + j0];
                for (int j = 0; j < std::min(BLOCK, nj - j0); ++j)
                    cij[j] *= beta;
            }

            // Accumulate the product alpha*A*B
            for (int k = 0; k < nk; ++k) {
                const double aik = a[i0 * nk + k] * alpha; // will change per i
                for (int i = i0; i < std::min(i0 + BLOCK, ni); ++i) {
                    const double aik_i = a[i * nk + k] * alpha;
                    double* cij = &c[i * nj + j0];
                    const double* bkj = &b[k * nj + j0];
                    for (int j = 0; j < std::min(BLOCK, nj - j0); ++j)
                        cij[j] += aik_i * bkj[j];
                }
            }
        }

    // Copy the result back into the 2‑D vector C
    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            C[i][j] = c[i * nj + j];

    delete[] a;
    delete[] b;
    delete[] c;
}
