```cpp
#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
    with help from Allison Lake, Ting Zhou, and Tian Jin,
    based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    /* Simple inline match function */
    auto match = [](int b1, int b2) { return (b1 + b2 == 3) ? 1 : 0; };

    /* Parallelisation over diagonals: j - i = d,       1 <= d < n */
    for (int d = 1; d < n; ++d) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i + d < n; ++i) {
            int j = i + d;
            int best = table[i][j];                     /* current value */

            /* prev cell in same row */
            if (j > 0) {
                int v = table[i][j-1];
                if (v > best) best = v;
            }
            /* prev cell in same column */
            if (i + 1 < n) {
                int v = table[i+1][j];
                if (v > best) best = v;
            }

            /* diagonal neighbour */
            if (i + 1 < n && j - 1 >= 0) {
                int v = table[i+1][j-1];
                if (i < j-1) {
                    v += match(seq[i], seq[j]);          /* pair match */
                }
                if (v > best) best = v;
            }

            /* split over k */
            int temp = best;
            for (int k = i + 1; k < j; ++k) {
                int v = table[i][k] + table[k+1][j];
                if (v > temp) temp = v;
            }
            best = temp;

            table[i][j] = best;
        }
    }
}
