#include <omp.h>

/*
 * Optimised LU decomposition kernel.
 *
 * The implementation keeps the exact algorithmic steps but
 * improves memory locality and enables vectorisation.
 * The outermost loop is *not* parallelised because
 * the standard LU decomposition is inherently sequential
 * (each row depends on all previously computed rows).
 *
 * Instead, we use local pointers to each row to avoid repeated
 * indirection through std::vector::operator[] and pre‑fetch
 * the necessary columns by iterating with raw pointers where possible.
 */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Ensure that the outer vector has n rows and each inner vector has at least n elements
    for (int i = 0; i < n; ++i) {
        A[i].resize(n);
    }

    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();            // pointer to current row
        // ---------- compute column i (rows < i) ----------
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            // Unroll the innermost loop a bit for vectorisation
            int k = 0;
            for (; k <= j - 4; k += 4) {
                sum += Ai[k]   * A[k][j];
                sum += Ai[k+1] * A[k+1][j];
                sum += Ai[k+2] * A[k+2][j];
                sum += Ai[k+3] * A[k+3][j];
            }
            for (; k < j; ++k) {
                sum += Ai[k] * A[k][j];
            }
            Ai[j] = (Ai[j] - sum) / A[j][j];
        }

        // ---------- compute row i (columns >= i) ----------
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            int k = 0;
            for (; k <= i - 4; k += 4) {
                sum += Ai[k]   * A[k][j];
                sum += Ai[k+1] * A[k+1][j];
                sum += Ai[k+2] * A[k+2][j];
                sum += Ai[k+3] * A[k+3][j];
            }
            for (; k < i; ++k) {
                sum += Ai[k] * A[k][j];
            }
            Ai[j] -= sum;
        }
    }
}
```
This version:
1. **Reduces indexing overhead** by replacing `A[i][j]` with raw pointers.
2. **Enables compiler vectorisation** through manual loop unrolling.
3. Maintains the exact mathematical behaviour of the original kernel.

