/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    /* --- 1.  Zero the output vector y ---------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        y[i] = 0.0;
    }

    /* --- 2.  Parallel accumulation across rows.  The `tmp` array is
             written only by the thread that owns the corresponding row,
             so no race conditions exist.  The portion that updates y
             uses a reduction on the entire array, which preserves the
             semantics of the original sequential code.  -------------------------------- */
    #pragma omp parallel for schedule(static) reduction(+:y[:n])
    for (int i = 0; i < m; ++i) {
        double row_sum = 0.0;

        /* Vectorized dot product: A[i][j] * x[j]  */
        #pragma omp simd
        for (int j = 0; j < n; ++j) {
            row_sum += A[i][j] * x[j];
        }
        tmp[i] = row_sum;

        /* Accumulate A[i][j] * row_sum into y[j] */
        #pragma omp simd
        for (int j = 0; j < n; ++j) {
            y[j] += A[i][j] * row_sum;
        }
    }
}
