#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    /* Main time‑step loop */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* ---------- Sweep 1: update v ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double *v_i      = v[i].data();
            double *p_i      = p[i].data();
            double *q_i      = q[i].data();
            double *u_i_m1   = u[i-1].data();
            double *u_i     = u[i].data();
            double *u_i_p1   = u[i+1].data();

            /* boundary rows */
            v_i[0] = 1.0;
            p_i[0] = 0.0;
            q_i[0] = v_i[0];

            /* forward pass */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = a * p_i[j-1] + b;
                p_i[j] = -c / denom;
                q_i[j] = (-d * u_i_m1[j-1] + (1.0 + 2.0 * d) * u_i[j] - f * u_i_p1[j] - a * q_i[j-1]) / denom;
            }

            v_i[n-1] = 1.0;

            /* backward pass */
            for (int j = n - 2; j >= 1; --j)
                v_i[j] = p_i[j] * v_i[j+1] + q_i[j];
        }

        /* ---------- Sweep 2: update u ---------- */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double *u_i      = u[i].data();
            double *p_i      = p[i].data();
            double *q_i      = q[i].data();
            double *v_i_m1   = v[i-1].data();
            double *v_i     = v[i].data();
            double *v_i_p1   = v[i+1].data();

            /* boundary columns */
            u_i[0] = 1.0;
            p_i[0] = 0.0;
            q_i[0] = u_i[0];

            /* forward pass */
            for (int j = 1; j < n - 1; ++j)
            {
                double denom = d * p_i[j-1] + e;
                p_i[j] = -f / denom;
                q_i[j] = (-a * v_i_m1[j] + (1.0 + 2.0 * a) * v_i[j] - c * v_i_p1[j] - d * q_i[j-1]) / denom;
            }

            u_i[n-1] = 1.0;

            /* backward pass */
            for (int j = n - 2; j >= 1; --j)
                u_i[j] = p_i[j] * u_i[j+1] + q_i[j];
        }
    }
}
