void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B) {

    constexpr double Inv8 = 0.125;
    // Create raw pointers to the innermost vectors for fast indexing
    std::vector<double*> A_ptr(n), B_ptr(n);
    for (int i = 0; i < n; ++i) {
        A_ptr[i] = A[i].data();   // pointer to the i‑th 2‑D slice
        B_ptr[i] = B[i].data();
    }

#pragma omp parallel for collapse(3) schedule(static)
    for (int t = 1; t <= tsteps; ++t) {
        // Update B from A
        for (int i = 1; i < n - 1; ++i) {
            double* Ai   = A_ptr[i];
            double* Aim1 = A_ptr[i - 1];
            double* Aim1 = A_ptr[i + 1];
            double* Bi   = B_ptr[i];
            for (int j = 1; j < n - 1; ++j) {
                double* Aj   = Ai + j * n;
                double* Ajm1 = Ai + (j - 1) * n;
                double* Ajp1 = Ai + (j + 1) * n;
                double* Bj   = Bi + j * n;
                double* Bjm1 = Bi + (j - 1) * n;
                double* Bjp1 = Bi + (j + 1) * n;
                for (int k = 1; k < n - 1; ++k) {
                    double val = Aj[k]                      // A[i][j][k]
                               + Inv8 * (Aim1[j * n + k]    // A[i+1][j][k]
                                         - 2.0 * Aj[k] + Ajm1[j * n + k])   // A[i-1][j][k]
                               + Inv8 * (Ajp1[k]           // A[i][j+1][k]
                                         - 2.0 * Aj[k] + Ajm1[j * n + k])   // A[i][j-1][k]
                               + Inv8 * (Aj[k + 1]          // A[i][j][k+1]
                                         - 2.0 * Aj[k] + Aj[k - 1]);           // A[i][j][k-1]
                    Bj[k] = val;
                }
            }
        }

        // Update A from B
        for (int i = 1; i < n - 1; ++i) {
            double* Bi   = B_ptr[i];
            double* Bim1 = B_ptr[i - 1];
            double* Bipl1 = B_ptr[i + 1];
            double* Ai   = A_ptr[i];
            for (int j = 1; j < n - 1; ++j) {
                double* Bj   = Bi + j * n;
                double* Bjm1 = Bi + (j - 1) * n;
                double* Bjp1 = Bi + (j + 1) * n;
                double* Aj   = Ai + j * n;
                double* Ajm1 = Ai + (j - 1) * n;
                double* Ajp1 = Ai + (j + 1) * n;
                for (int k = 1; k < n - 1; ++k) {
                    double val = Bj[k]                      // B[i][j][k]
                               + Inv8 * (Bipl1[j * n + k]    // B[i+1][j][k]
                                         - 2.0 * Bj[k] + Bim1[j * n + k])   // B[i-1][j][k]
                               + Inv8 * (Bjp1[k]           // B[i][j+1][k]
                                         - 2.0 * Bj[k] + Bjm1[j * n + k])   // B[i][j-1][k]
                               + Inv8 * (Bj[k + 1]          // B[i][j][k+1]
                                         - 2.0 * Bj[k] + Bj[k - 1]);           // B[i][j][k-1];
                    Aj[k] = val;
                }
            }
        }
    }
}
