#include <cmath>
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised Deriche filter kernel.
 * The function signature must stay unchanged.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants (all float for speed) */
    const float fa  = static_cast<float>(alpha);
    const float e   = std::exp(-fa);
    const float ee  = e * e;
    const float k   = 1.0f - e * (1.0f - e) / (1.0f + 2.0f * fa * e - ee);

    const float a1  =  k;
    const float a5  =  k;
    const float a2  =  k * e * (fa - 1.0f);
    const float a6  =  k * e * (fa - 1.0f);
    const float a3  =  k * e * (fa + 1.0f);
    const float a7  =  k * e * (fa + 1.0f);
    const float a4  = -k * ee;
    const float a8  = -k * ee;
    const float b1  = std::pow(2.0f, -fa);
    const float b2  = -ee;
    const float c   = 1.0f;                /* c1 and c2 are identical */

    /* Row‑wise forward recursion */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = imgIn[i][j];
            const float y = a1 * x + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            xm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* Row‑wise backward recursion */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float x = imgIn[i][j];
            const float y = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            xp2 = xp1;   xp1 = x;   yp2 = yp1;   yp1 = y;
        }
    }

    /* Combine forward/backward results */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);
        }
    }

    /* Column‑wise forward recursion (on imgOut) */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float ym1 = 0.0f, ym2 = 0.0f, tm1 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float x = imgOut[i][j];
            const float y = a5 * x + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1[i][j] = y;
            tm1 = x;  ym2 = ym1;  ym1 = y;
        }
    }

    /* Column‑wise backward recursion (on imgOut) */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float yp1 = 0.0f, yp2 = 0.0f, tp1 = 0.0f, tp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float x = imgOut[i][j];
            const float y = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2[i][j] = y;
            tp2 = tp1;   tp1 = x;   yp2 = yp1;   yp1 = y;
        }
    }

    /* Final combination */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c * (y1[i][j] + y2[i][j]);
        }
    }
}
