#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Parallelise over the j‑loop.  For a fixed i each j operates on
       completely independent entries of C.  The inner k‑loop touches
       earlier rows C[k][j] but only for the same j, so there is no
       data race. */
#pragma omp parallel for schedule(static) shared(C,A,B,alpha,beta,m,n)
    for (int i = 0; i < m; ++i) {
        double betaC = beta;            // copy to a local for speed
        double alphaC = alpha;          // copy to a local for speed
        for (int j = 0; j < n; ++j) {
            double temp2 = 0.0;
            double b_ij = B[i][j];
            double a_ii = A[i][i];

            /* Unroll a few iterations of the k‑loop for small i. */
            int k = 0;
            for (; k + 7 < i; k += 8) {
                /* Load A[i][k..k+7] and B[i][j] once */
                double ajk0 = A[i][k];
                double ajk1 = A[i][k + 1];
                double ajk2 = A[i][k + 2];
                double ajk3 = A[i][k + 3];
                double ajk4 = A[i][k + 4];
                double ajk5 = A[i][k + 5];
                double ajk6 = A[i][k + 6];
                double ajk7 = A[i][k + 7];

                double bik0 = b_ij * ajk0;
                double bik1 = b_ij * ajk1;
                double bik2 = b_ij * ajk2;
                double bik3 = b_ij * ajk3;
                double bik4 = b_ij * ajk4;
                double bik5 = b_ij * ajk5;
                double bik6 = b_ij * ajk6;
                double bik7 = b_ij * ajk7;

                C[k][j] += alphaC * bik0;
                C[k + 1][j] += alphaC * bik1;
                C[k + 2][j] += alphaC * bik2;
                C[k + 3][j] += alphaC * bik3;
                C[k + 4][j] += alphaC * bik4;
                C[k + 5][j] += alphaC * bik5;
                C[k + 6][j] += alphaC * bik6;
                C[k + 7][j] += alphaC * bik7;

                temp2 += B[k][j] * ajk0;
                temp2 += B[k + 1][j] * ajk1;
                temp2 += B[k + 2][j] * ajk2;
                temp2 += B[k + 3][j] * ajk3;
                temp2 += B[k + 4][j] * ajk4;
                temp2 += B[k + 5][j] * ajk5;
                temp2 += B[k + 6][j] * ajk6;
                temp2 += B[k + 7][j] * ajk7;
            }
            for (; k < i; ++k) {
                double ajk = A[i][k];
                double bik = b_ij * ajk;
                C[k][j] += alphaC * bik;
                temp2 += B[k][j] * ajk;
            }
            C[i][j] = betaC * C[i][j] + alphaC * b_ij * a_ii + alphaC * temp2;
        }
    }
}
